    // Read item 1, item 2 (last=true so 2nd item passes even though test fails after)
    // Then read again to get ended, then read once more
    through(null, (e: any, d: any) => { if (!e) results.push(d); });
    through(null, (e: any, d: any) => { if (!e) results.push(d); else errors.push(e); });
    // After 2 items, next read triggers terminate (last=true)
    through(null, (e: any, d: any) => { errors.push(e || 'ended'); });
    // After terminate, last should be false; this should NOT call terminate again
    through(null, (e: any, d: any) => { 
